import java.awt.image.*;
import java.awt.*;
public class StretchBug {
    static BufferedImage scaleFixed(BufferedImage src) {
        // desired: maintain aspect ratio to fit in 200x200
        BufferedImage out = new BufferedImage(200, 200, src.getType());
        Graphics2D g = out.createGraphics();
        g.drawImage(src, 0, 0, 200, 200, null);  // bug: ignores aspect ratio
        g.dispose();
        return out;
    }
}
